7	export class AutoImageProcessor {
8	
9	    /** @type {typeof ImageProcessor.from_pretrained} */
10	    static async from_pretrained(pretrained_model_name_or_path, options={}) {
11	
12	        const preprocessorConfig = await getModelJSON(pretrained_model_name_or_path, IMAGE_PROCESSOR_NAME, true, options);
13	
14	        // Determine image processor class
15	        const key = preprocessorConfig.image_processor_type ?? preprocessorConfig.feature_extractor_type;
16	        let image_processor_class = AllImageProcessors[key?.replace(/Fast$/, '')];
17	
18	        if (!image_processor_class) {
19	            if (key !== undefined) {
20	                // Only log a warning if the class is not found and the key is set.
21	                console.warn(`Image processor type '${key}' not found, assuming base ImageProcessor. Please report this at ${GITHUB_ISSUE_URL}.`)
22	            }
23	            image_processor_class = ImageProcessor;
24	        }
25	
26	        // Instantiate image processor
27	        return new image_processor_class(preprocessorConfig);
28	    }
29	}
