82	/**
83	 * Helper function to split a string on a regex, but keep the delimiters.
84	 * This is required, because the JavaScript `.split()` method does not keep the delimiters,
85	 * and wrapping in a capturing group causes issues with existing capturing groups (due to nesting).
86	 * @param {string} text The text to split.
87	 * @param {RegExp} regex The regex to split on.
88	 * @returns {string[]} The split string.
89	 */
90	function regexSplit(text, regex) {
91	    const result = [];
92	    let prev = 0;
93	    for (const match of text.matchAll(regex)) {
94	        const fullMatch = match[0];
95	        if (prev < match.index) {
96	            result.push(text.slice(prev, match.index));
97	        }
98	        if (fullMatch.length > 0) {
99	            result.push(fullMatch);
