10	 * const audio = await read_audio('https://huggingface.co/datasets/Narsil/asr_dummy/resolve/main/mlk.flac', 16000);
11	 * const { input_features } = await processor(audio);
12	 * // Tensor {
13	 * //   data: Float32Array(240000) [0.4752984642982483, 0.5597258806228638, 0.56434166431427, ...],
14	 * //   dims: [1, 80, 3000],
15	 * //   type: 'float32',
16	 * //   size: 240000,
17	 * // }
18	 * ```
19	 * 
20	 * @module processors
21	 */
22	import { PROCESSOR_NAME, CHAT_TEMPLATE_NAME } from '../utils/constants.js';
23	import {
24	    Callable,
25	} from '../utils/generic.js';
26	import { getModelJSON, getModelText } from '../utils/hub.js';
27	
28	/**
29	 * @typedef {Object} ProcessorProperties Additional processor-specific properties.
30	 * @typedef {import('../utils/hub.js').PretrainedOptions & ProcessorProperties} PretrainedProcessorOptions
31	 * @typedef {import('../tokenizers.js').PreTrainedTokenizer} PreTrainedTokenizer
32	 */
33	
34	
35	/**
36	 * Represents a Processor that extracts features from an input.
37	 */
38	export class Processor extends Callable {
39	    static classes = [
40	        'image_processor_class',
41	        'tokenizer_class',
42	        'feature_extractor_class',
43	    ]
44	    static uses_processor_config = false;
45	    static uses_chat_template_file = false;
46	
47	    /**
48	     * Creates a new Processor with the given components
49	     * @param {Object} config 
50	     * @param {Record<string, Object>} components 
51	     * @param {string} chat_template
52	     */
53	    constructor(config, components, chat_template) {
54	        super();
55	        this.config = config;
56	        this.components = components;
57	        this.chat_template = chat_template;
58	    }
59	
60	    /**
61	     * @returns {import('./image_processors_utils.js').ImageProcessor|undefined} The image processor of the processor, if it exists.
62	     */
63	    get image_processor() {
64	        return this.components.image_processor;
65	    }
66	
67	    /**
68	     * @returns {PreTrainedTokenizer|undefined} The tokenizer of the processor, if it exists.
69	     */
70	    get tokenizer() {
71	        return this.components.tokenizer;
72	    }
73	
74	    /**
75	     * @returns {import('./feature_extraction_utils.js').FeatureExtractor|undefined} The feature extractor of the processor, if it exists.
76	     */
77	    get feature_extractor() {
78	        return this.components.feature_extractor;
79	    }
80	
81	    /**
82	     * @param {Parameters<PreTrainedTokenizer['apply_chat_template']>[0]} messages
83	     * @param {Parameters<PreTrainedTokenizer['apply_chat_template']>[1]} options
84	     * @returns {ReturnType<PreTrainedTokenizer['apply_chat_template']>}
85	     */
86	    apply_chat_template(messages, options = {}) {
87	        if (!this.tokenizer) {
88	            throw new Error('Unable to apply chat template without a tokenizer.');
89	        }
90	        return this.tokenizer.apply_chat_template(messages, {
91	            tokenize: false, // default to false
92	            chat_template: this.chat_template ?? undefined,
93	            ...options,
94	        });
95	    }
96	
97	    /**
98	     * @param {Parameters<PreTrainedTokenizer['batch_decode']>} args
99	     * @returns {ReturnType<PreTrainedTokenizer['batch_decode']>}
100	     */
101	    batch_decode(...args) {
102	        if (!this.tokenizer) {
103	            throw new Error('Unable to decode without a tokenizer.');
104	        }
105	        return this.tokenizer.batch_decode(...args);
106	    }
107	
108	    /**
109	     * @param {Parameters<PreTrainedTokenizer['decode']>} args
110	     * @returns {ReturnType<PreTrainedTokenizer['decode']>}
111	     */
112	    decode(...args) {
113	        if (!this.tokenizer) {
114	            throw new Error('Unable to decode without a tokenizer.');
115	        }
116	        return this.tokenizer.decode(...args);
117	    }
118	
119	
120	    /**
121	     * Calls the feature_extractor function with the given input.
122	     * @param {any} input The input to extract features from.
123	     * @param {...any} args Additional arguments.
124	     * @returns {Promise<any>} A Promise that resolves with the extracted features.
125	     */
126	    async _call(input, ...args) {
127	        for (const item of [this.image_processor, this.feature_extractor, this.tokenizer]) {
128	            if (item) {
129	                return item(input, ...args);
130	            }
131	        }
132	        throw new Error('No image processor, feature extractor, or tokenizer found.');
133	    }
134	
135	
136	    /**
137	     * Instantiate one of the processor classes of the library from a pretrained model.
138	     * 
139	     * The processor class to instantiate is selected based on the `image_processor_type` (or `feature_extractor_type`; legacy)
140	     * property of the config object (either passed as an argument or loaded from `pretrained_model_name_or_path` if possible)
141	     * 
142	     * @param {string} pretrained_model_name_or_path The name or path of the pretrained model. Can be either:
143	     * - A string, the *model id* of a pretrained processor hosted inside a model repo on huggingface.co.
144	     *   Valid model ids can be located at the root-level, like `bert-base-uncased`, or namespaced under a
145	     *   user or organization name, like `dbmdz/bert-base-german-cased`.
146	     * - A path to a *directory* containing processor files, e.g., `./my_model_directory/`.
147	     * @param {PretrainedProcessorOptions} options Additional options for loading the processor.
148	     * 
149	     * @returns {Promise<Processor>} A new instance of the Processor class.
150	     */
151	    static async from_pretrained(pretrained_model_name_or_path, options={}) {
152	
153	        const [config, components, chat_template] = await Promise.all([
154	            // TODO:
155	            this.uses_processor_config
156	                ? getModelJSON(pretrained_model_name_or_path, PROCESSOR_NAME, true, options)
157	                : {},
158	            Promise.all(
159	                this.classes
160	                    .filter((cls) => cls in this)
161	                    .map(async (cls) => {
162	                        const component = await this[cls].from_pretrained(pretrained_model_name_or_path, options);
163	                        return [cls.replace(/_class$/, ''), component];
164	                    })
165	            ).then(Object.fromEntries),
166	            this.uses_chat_template_file
167	                ? getModelText(pretrained_model_name_or_path, CHAT_TEMPLATE_NAME, true, options)
168	                : null,
169	        ]);
170	
171	        return new this(config, components, chat_template);
172	    }
173	}
