6	export class Qwen2VLProcessor extends Processor {
7	    static image_processor_class = AutoImageProcessor
8	    static tokenizer_class = AutoTokenizer
9	
10	    /**
11	     * 
12	     * @param {string|string[]} text 
13	     * @param {RawImage|RawImage[]} images 
14	     * @param  {...any} args 
15	     * @returns {Promise<any>}
16	     */
17	    async _call(text, images = null, ...args) {
18	
19	        if (!Array.isArray(text)) {
20	            text = [text];
21	        }
22	
23	        let image_inputs, image_grid_thw;
24	
25	        if (images) {
26	            image_inputs = await this.image_processor(images);
27	            image_grid_thw = image_inputs.image_grid_thw;
28	        }
29	
30	        if (image_grid_thw) {
31	            // @ts-expect-error TS2551
32	            let merge_length = this.image_processor.config.merge_size ** 2;
33	            let index = 0;
34	
35	            const image_grid_thw_list = image_grid_thw.tolist();
36	            text = text.map(t => {
37	                while (t.includes("<|image_pad|>")) {
