39	                    t = t.replace("<|image_pad|>", "<|placeholder|>".repeat(Math.floor(prod / merge_length)));
40	                }
41	                return t.replaceAll("<|placeholder|>", "<|image_pad|>");
42	            });
43	        }
44	
45	        const text_inputs = this.tokenizer(text);
46	
47	        return {
48	            ...text_inputs,
