1	import { Processor } from "../../base/processing_utils.js";
2	import { AutoImageProcessor } from "../auto/image_processing_auto.js";
3	import { AutoTokenizer } from "../../tokenizers.js";
4	import { RawImage } from "../../utils/image.js";
5	
6	const IMAGE_TOKEN = "<|image|>";
7	const IMAGE_TOKEN_PATTERN = /<\|image_\d+\|>/g;
8	
9	export class Phi3VProcessor extends Processor {
10	    static image_processor_class = AutoImageProcessor
11	    static tokenizer_class = AutoTokenizer
12	
13	    /**
14	     * 
15	     * @param {string|string[]} text 
16	     * @param {RawImage|RawImage[]} images 
17	     * @param  { { padding?: boolean, truncation?: boolean, num_crops?: number } | undefined } options
18	     * @returns {Promise<any>}
19	     */
20	    async _call(text, images = null, {
21	        padding = true,
22	        truncation = true,
23	        num_crops = null,
24	    } = {}) {
25	
26	        if (!Array.isArray(text)) {
27	            text = [text];
28	        }
29	
30	        let text_inputs, image_inputs;
31	        if (images) {
32	            image_inputs = await this.image_processor(images, { num_crops });
33	            const { num_img_tokens } = image_inputs;
34	
35	            // The original implementation adds a bos_token before the image tokens
36	            // TODO: Check if this affects performance, since it looks like a bug in the original implementation
37	            const prompt_chunks = text.map((t, i) => t.split(IMAGE_TOKEN_PATTERN).join(IMAGE_TOKEN.repeat(num_img_tokens[i])));
38	
39	            text_inputs = this.tokenizer(prompt_chunks, { padding, truncation });
40	
41	            // The model expects image tokens to be negative, so we negate the image token ids
42	            const image_token_id = this.tokenizer.model.convert_tokens_to_ids([IMAGE_TOKEN])[0];
43	            text_inputs.input_ids.map_(id => (id == image_token_id) ? -id : id);
44	        } else {
45	            text_inputs = this.tokenizer(text);
46	        }
47	
48	        return {
49	            ...text_inputs,
50	            ...image_inputs,
51	        }
52	    }
53	}
