2	import { Processor } from "../../base/processing_utils.js";
3	import { AutoImageProcessor } from "../auto/image_processing_auto.js";
4	import { AutoTokenizer } from "../../tokenizers.js";
5	import { RawImage } from "../../utils/image.js";
6	import { count } from "../../utils/core.js";
7	
8	/**
9	 * Prompt with expanded image tokens for when the image is split into patches.
10	 * @private
11	 */
12	function _prompt_split_image(image_seq_len, image_rows, image_cols, fake_token_around_image, image_token, global_img_token) {
13	    let text_split_images = "";
14	    for (let n_h = 0; n_h < image_rows; ++n_h) {
15	        for (let n_w = 0; n_w < image_cols; ++n_w) {
16	            text_split_images += (
17	                fake_token_around_image +
18	                `<row_${n_h + 1}_col_${n_w + 1}>` +
19	                image_token.repeat(image_seq_len)
20	            );
21	        }
22	        text_split_images += "\n";
23	    }
24	
25	    text_split_images += (
26	        `\n${fake_token_around_image}` +
27	        `${global_img_token}` +
28	        image_token.repeat(image_seq_len) +
29	        `${fake_token_around_image}`
30	    );
31	    return text_split_images;
32	}
33	
34	/**
35	 * Prompt with expanded image tokens for a single image.
36	 * @private
37	 */
38	function _prompt_single_image(image_seq_len, fake_token_around_image, image_token, global_img_token) {
39	    return (
40	        `${fake_token_around_image}` +
41	        `${global_img_token}` +
42	        image_token.repeat(image_seq_len) +
43	        `${fake_token_around_image}`
44	    );
45	}
46	
47	function get_image_prompt_string(image_rows, image_cols, image_seq_len, fake_token_around_image, image_token, global_img_token) {
48	    if (image_rows === 0 && image_cols === 0) {
49	        return _prompt_single_image(
50	            image_seq_len,
51	            fake_token_around_image,
52	            image_token,
53	            global_img_token
54	        );
55	    }
56	    return _prompt_split_image(
57	        image_seq_len, image_rows, image_cols, fake_token_around_image, image_token, global_img_token
58	    );
59	}
60	
61	
62	export class Idefics3Processor extends Processor {
63	    static image_processor_class = AutoImageProcessor
64	    static tokenizer_class = AutoTokenizer
65	    static uses_processor_config = true;
66	
67	    fake_image_token = "<fake_token_around_image>";
68	    image_token = "<image>";
69	    global_img_token = "<global-img>";
70	
71	    /**
72	     * 
73	     * @param {string|string[]} text 
74	     * @param {RawImage|RawImage[]|RawImage[][]} images  
75	     * @returns {Promise<any>}
76	     */
77	    async _call(text, images = null, options = {}) {
78	        options.return_row_col_info ??= true;
79	
80	        let image_inputs;
81	
82	        if (images) {
83	            image_inputs = await this.image_processor(images, options);
84	        }
85	
86	        // NOTE: We assume text is present
87	        if (!Array.isArray(text)) {
88	            text = [text];
89	        }
90	
91	        const image_rows = image_inputs.rows ?? [new Array(text.length).fill(0)];
92	        const image_cols = image_inputs.cols ?? [new Array(text.length).fill(0)];
93	
94	        const image_seq_len = this.config.image_seq_len;
95	        const n_images_in_text = []
96	        const prompt_strings = [];
97	        for (let i = 0; i < text.length; ++i) {
98	            const sample = text[i];
99	            const sample_rows = image_rows[i];
100	            const sample_cols = image_cols[i];
101	
102	            n_images_in_text.push(count(sample, this.image_token));
103	
104	            // Replace the image token with fake tokens around the expanded image token sequence of length `image_seq_len`
105	            const image_prompt_strings = sample_rows.map(
106	                (n_rows, j) => get_image_prompt_string(
107	                    n_rows,
108	                    sample_cols[j],
109	                    image_seq_len,
110	                    this.fake_image_token,
111	                    this.image_token,
112	                    this.global_img_token,
113	                )
114	            );
115	
116	            const split_sample = sample.split(this.image_token);
117	            if (split_sample.length === 0) {
118	                throw new Error("The image token should be present in the text.");
119	            }
120	
121	            // Place in the image prompt strings where the image tokens are
122	            let new_sample = split_sample[0];
123	            for (let j = 0; j < image_prompt_strings.length; ++j) {
124	                new_sample += image_prompt_strings[j] + split_sample[j + 1];
125	            }
126	            prompt_strings.push(new_sample);
127	        }
128	
129	        const text_inputs = this.tokenizer(prompt_strings);
130	
131	        return {
132	            ...text_inputs,
133	            ...image_inputs,
134	        }
135	    }
136	}
