2	import { Processor } from "../../base/processing_utils.js";
3	import { AutoImageProcessor } from "../auto/image_processing_auto.js";
4	import { AutoTokenizer } from "../../tokenizers.js";
5	import { mergeArrays } from "../../utils/core.js";
6	import { Tensor } from "../../utils/tensor.js";
7	import { RawImage } from "../../utils/image.js";
8	
9	export class VLChatProcessor extends Processor {
10	    static image_processor_class = AutoImageProcessor
11	    static tokenizer_class = AutoTokenizer
12	    static uses_processor_config = true;
13	
14	    constructor(config, components, chat_template) {
15	        super(config, components, chat_template);
16	
17	        this.image_tag = this.config.image_tag;
18	        this.image_start_tag = this.config.image_start_tag;
19	        this.image_end_tag = this.config.image_end_tag;
20	        this.num_image_tokens = this.config.num_image_tokens;
21	    }
22	
23	    /**
24	     * @typedef {Object} MultimodalMessageProperties Additional properties for multimodal messages.
25	     * @property {(RawImage | string | URL)[]} [images] The images in the message.
26	     * @typedef {(import('../../tokenizers.js').Message & MultimodalMessageProperties)[]} MultimodalConversation The conversation possibly containing multimodal inputs.
27	     */
28	
29	    /**
30	     * @typedef {Object} VLCChatProcessorResult The processed input.
31	     * @property {Tensor} input_ids The input IDs.
32	     * @property {Tensor} attention_mask The attention mask.
33	     * @property {Tensor} images_seq_mask The image sequence mask.
34	     * @property {Tensor} images_emb_mask The image embedding mask.
35	     */
36	
37	    /**
38	     * @param {MultimodalConversation} conversation The chat messages to process.
39	     * @param {Object} options Additional options for processing.
40	     * @param {RawImage|RawImage[]} [options.images] The images to process, if not set in the conversation.
41	     * @param {string} [options.chat_template="default"] The chat template to use.
42	     * @returns {Promise<VLCChatProcessorResult | VLCChatProcessorResult & import('../../base/image_processors_utils.js').ImageProcessorResult>} The processed input.
43	     */
44	    async _call(conversation, {
45	        images = null,
46	        chat_template = "default",
47	    }={}) {
48	        if (!images) {
49	            images = await Promise.all(
50	                conversation
51	                    .filter((msg) => msg.images)
52	                    .flatMap((msg) => msg.images)
53	                    .map((img) => RawImage.read(img))
54	            );
55	        } else if (!Array.isArray(images)) {
56	            images = [images];
57	        }
58	
59	        const tokenizer = this.tokenizer;
60	        const result = tokenizer.apply_chat_template(conversation, {
61	            tokenize: false,
62	            add_generation_prompt: true,
63	            chat_template,
64	        });
65	
66	        const encode = (text) => tokenizer.encode(text, { add_special_tokens: false });
67	        const parts = (/** @type {string} */(result))
68	            .split(this.image_tag);
69	        const num_images = parts.length - 1;
70	        if (images.length !== num_images) {
71	            throw new Error(`Number of images provided (${images.length}) does not match number of "${this.image_tag}" image tags (${num_images})`);
72	        }
73	
74	        const [
75	            image_placeholder_tag_id,
76	            image_start_tag_id,
77	            image_end_tag_id,
78	        ] = tokenizer.model.convert_tokens_to_ids([
79	            this.image_tag,
80	            this.image_start_tag,
81	            this.image_end_tag,
82	        ]);
83	
84	        let input_ids = encode(parts[0]);
85	        let images_seq_mask = new Array(input_ids.length).fill(false);
86	        for (let i = 1; i < parts.length; ++i) {
87	            const placeholder_image_tokens = new Array(this.num_image_tokens).fill(image_placeholder_tag_id);
88	            const tokens = encode(parts[i]);
89	            input_ids = mergeArrays(
90	                input_ids,
91	                [image_start_tag_id], placeholder_image_tokens, [image_end_tag_id],
92	                tokens,
93	            );
94	            const image_mask = new Array(this.num_image_tokens).fill(true);
95	            images_seq_mask = mergeArrays(
96	                images_seq_mask,
97	                [false], image_mask, [false],
98	                new Array(tokens.length).fill(false),
99	            );
100	        }
101	
102	        const dims = [1, input_ids.length];
103	        const final = {
104	            input_ids: new Tensor('int64', input_ids, dims),
105	            attention_mask: new Tensor('int64', new Array(input_ids.length).fill(1), dims),
106	            images_seq_mask: new Tensor('bool', images_seq_mask, dims),
107	            images_emb_mask: new Tensor(
108	                'bool',
109	                new Array(num_images * this.num_image_tokens).fill(true),
110	                [1, num_images, this.num_image_tokens],
111	            ),
112	        }
113	
114	        if (images && images.length > 0) {
115	            const image_inputs = await this.image_processor(images);
116	            // Set the batch_size dimension to 1
117	            image_inputs.pixel_values.unsqueeze_(0);
118	            return { ...final, ...image_inputs };
119	        }
120	
121	        return final;
122	    }
123	}
